import{_ as s,c as i,o as n,ae as t}from"./chunks/framework.Cd-3tpCq.js";const g=JSON.parse('{"title":"🙈 Le fichier .gitignore","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/gitignore.md","filePath":"drupal-project/installation/gitignore.md"}'),r={name:"drupal-project/installation/gitignore.md"};function a(o,e,l,p,c,d){return n(),i("div",null,e[0]||(e[0]=[t(`<h1 id="🙈-le-fichier-gitignore" tabindex="-1">🙈 Le fichier .gitignore <a class="header-anchor" href="#🙈-le-fichier-gitignore" aria-label="Permalink to &quot;🙈 Le fichier .gitignore&quot;">​</a></h1><p>Le fichier <em>.gitignore</em> est un fichier de configuration qui indique à <strong>Git</strong> quels fichiers et dossiers ignorer lors des opérations de versionnement. Il permet d&#39;éviter d&#39;ajouter au dépôt des fichiers qui ne devraient pas être partagés.</p><p>Ce qui est très pratique pour :</p><ul><li><strong>Eviter de versionner</strong> les fichiers de configuration personnels, comme ceux de l&#39;IDE par exemple.</li><li><strong>Protéger les informations sensibles</strong> en évitant que les fichiers <em>.env</em> et les mots de passe soient visibles dans le git.</li><li><strong>Réduire la taille du dépôt</strong> en excluant les dossiers de dépendances comme <em>vendor/</em> ou <em>node_modules/</em>.</li><li><strong>Eviter les conflits inutiles</strong>, comme sur les fichiers de logs ou de cache qui changent constamment.</li></ul><p>Créez le fichier <em>.gitignore</em> à la racine du projet</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">touch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .gitignore</span></span></code></pre></div><h2 id="ignorer-des-dossiers-et-des-fichiers" tabindex="-1">Ignorer des dossiers et des fichiers <a class="header-anchor" href="#ignorer-des-dossiers-et-des-fichiers" aria-label="Permalink to &quot;Ignorer des dossiers et des fichiers&quot;">​</a></h2><p>Nous allons ignorer les fichiers suivants :</p><ul><li>Les fichiers de <strong>configuration de l&#39;IDE</strong> : <strong>PHPSTORM</strong>, <strong>VSCode</strong> et autres IDE ajoute des fichiers de configuration dans les projets. Comme ces fichiers ne concerne que la configuration de votre IDE, il est préférable de les exclure du versionnement.</li><li>Les <strong>dépendances</strong> et modules contrib de <strong>Drupal</strong> : comme nous utilisons <strong>Composer</strong> pour gérer les dépendances, il est préférable d&#39;exclure les dossiers associés pour éviter de surcharger le dépôt.</li><li>Les fichiers <strong>auto-générés</strong> par <strong>Drupal</strong> : à chaque <code>composer install</code> ou <code>composer update</code>, <strong>Drupal</strong> génère et met à jour certains fichiers. Les versionner est donc inutile.</li><li>Les fichiers <strong>générés par les utilisateurs</strong> : certains fichiers sont créés par les utilisateurs. Par exemple, si vous ajoutez une image sur votre article de blog, l&#39;image sera enregistrée dans un dossier spécifique. Les contenus étant liés à l&#39;environnement il est préférable d&#39;exclure ces dossiers pour éviter de surcharger le dépôt.</li></ul><p>Ouvrez donc le fichier <code>.gitignore</code> et ajoutez le code suivant :</p><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># IDE files</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.idea/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.vscode/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ignore dependencies managed with Composer.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/vendor/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/web/core/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/web/modules/contrib/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/web/themes/contrib/</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/web/profiles/contrib/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ignore auto-generated files</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web/.htaccess</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ignore paths that contain user-generated content.</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web/sites/*/files</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">web/sites/*/private</span></span></code></pre></div><div class="warning custom-block"><p class="custom-block-title">⚠️ Ce fichier n&#39;est pas statique</p><p>Au fur et à mesure de notre projet, nous reviendrons sur ce fichier pour le mettre à jour en fonction de nos besoins.</p></div><div class="info custom-block"><p class="custom-block-title">Notre tout premier module</p><p>Pour faciliter la gestion du projet, avant d&#39;aller plus loin dans la formation je vous propose de découvrir et d&#39;installer notre tout premier module : <a href="/drupal-project/installation/drush.html">Drush</a></p></div>`,13)]))}const h=s(r,[["render",a]]);export{g as __pageData,h as default};
